defs.script:

function pulseEffect(evt) {
  var el = evt.currentTarget;
  el.style.transform = "scale(0.9)";
  var origTransform = el.getAttribute("style");
  setTimeout(function() {
    el.style.transform = ""; // Reset inline transform so CSS takes over
  }, 150);
}

document.addEventListener('DOMContentLoaded', function() {
  var svg = document.querySelector('svg');
  var lens = document.querySelector('.lens-fill');
  var dot = document.querySelector('.center-dot');

  document.addEventListener('mousemove', function(e) {
    if (!svg || !lens || !dot) return;
    var pt = svg.createSVGPoint();
    pt.x = e.clientX;
    pt.y = e.clientY;
    var cursorPt = pt.matrixTransform(svg.getScreenCTM().inverse());

    var dx = (cursorPt.x - 480) * 0.03;
    var dy = (cursorPt.y - 340) * 0.03;
    lens.setAttribute('transform', 'translate(' + dx + ',' + dy + ')');
    dot.setAttribute('transform', 'translate(' + (dx*1.8) + ',' + (dy*1.8) + ')');
  });
});
